import{_ as s,H as t,f as n,i as e}from"./chunks/framework.BHvCMIhP.js";const u=JSON.parse('{"title":"寄存器式 VM","description":"","frontmatter":{},"headers":[],"relativePath":"interpreterLearning/23-寄存器式VM.md","filePath":"interpreterLearning/23-寄存器式VM.md","lastUpdated":1778496697000}'),o={name:"interpreterLearning/23-寄存器式VM.md"};function p(i,a,d,l,r,c){return t(),n("div",null,[...a[0]||(a[0]=[e(`<h1 id="寄存器式-vm" tabindex="-1">寄存器式 VM <a class="header-anchor" href="#寄存器式-vm" aria-label="Permalink to &quot;寄存器式 VM&quot;">​</a></h1><p>栈式 VM 是教科书的开端,但<strong>真正在生产里被很多语言选中的反而是寄存器式</strong>——Lua 5.0+、Android Dalvik、.NET CoreCLR、Erlang BEAM、V8 Ignition(半个)全是。<strong>为什么?同样一段代码,寄存器式字节码指令数能少 30-40%、dispatch 次数少 30%、解释速度快 30%</strong>——Roberto Ierusalimschy 团队 2005 年的论文有数据。栈式赢在简洁、编译器好写;寄存器式赢在性能、读起来像汇编。<strong>这一篇做对比,不写实现</strong>——本系列 Mochi 走栈式路线,但你必须懂这个分叉。</p><blockquote><p>一句话先记住:<strong>寄存器式 = 字节码直接编号&quot;虚拟寄存器&quot;(其实是数组下标)、每条指令带 3 个操作数</strong>——指令更长、总数更少、dispatch 次数少,<strong>Lua / Dalvik 选这条因为快 30%</strong>,代价是编译器要做寄存器分配。</p></blockquote><hr><h2 id="一、寄存器式是什么" tabindex="-1">一、寄存器式是什么 <a class="header-anchor" href="#一、寄存器式是什么" aria-label="Permalink to &quot;一、寄存器式是什么&quot;">​</a></h2><p><strong>寄存器式(register-based)VM</strong>:每条指令直接指定<strong>操作数从哪儿读、结果写哪儿</strong>——读写位置是「虚拟寄存器编号」,<strong>实际上就是当前函数局部变量数组的下标</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ADD R3 R1 R2     ; R3 = R1 + R2</span></span>
<span class="line"><span>MOVE R0 R3       ; R0 = R3</span></span></code></pre></div><p>没有表达式栈这个东西,所有中间值都落在&quot;寄存器&quot;(局部变量 slot)上。「虚拟」是因为它不是 CPU 的物理寄存器——VM 跑起来这些 R0/R1/R2 其实是 <code>locals[0]</code>、<code>locals[1]</code>、<code>locals[2]</code>,编码上当寄存器用。</p><hr><h2 id="二、对比-a-b-c-两种字节码" tabindex="-1">二、对比:<code>a = b + c</code> 两种字节码 <a class="header-anchor" href="#二、对比-a-b-c-两种字节码" aria-label="Permalink to &quot;二、对比:\`a = b + c\` 两种字节码&quot;">​</a></h2><p>栈式(Mochi / JVM 风格):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>LOAD_LOCAL b     ; 4 条指令,3 次 push,1 次 pop</span></span>
<span class="line"><span>LOAD_LOCAL c</span></span>
<span class="line"><span>ADD</span></span>
<span class="line"><span>STORE_LOCAL a</span></span></code></pre></div><p>寄存器式(Lua 风格):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ADD Ra Rb Rc     ; 1 条指令,0 次栈操作</span></span></code></pre></div><p>差异本质:</p><table tabindex="0"><thead><tr><th>维度</th><th>栈式</th><th>寄存器式</th></tr></thead><tbody><tr><td>单条指令长度</td><td>1-2 字节</td><td>4 字节(op + 3 操作数编号)</td></tr><tr><td>指令总数</td><td>多</td><td>少 30-40%</td></tr><tr><td>dispatch 次数</td><td>多</td><td>少 30%</td></tr><tr><td>总字节数</td><td>接近</td><td>接近(指令少但每条长)</td></tr><tr><td>编译器复杂度</td><td>简单(一遍递归 emit)</td><td>复杂(要做寄存器分配)</td></tr><tr><td>字节码验证</td><td>容易(栈高度静态可算)</td><td>难</td></tr></tbody></table><p><strong>寄存器式不是&quot;用更少字节存程序&quot;,而是&quot;用更少 dispatch 跑完程序&quot;</strong>——dispatch 是解释器最贵的一步,<strong>少 30% 就是真的快 30%</strong>。</p><hr><h2 id="三、谁选什么" tabindex="-1">三、谁选什么 <a class="header-anchor" href="#三、谁选什么" aria-label="Permalink to &quot;三、谁选什么&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>栈式                          寄存器式</span></span>
<span class="line"><span>─────────────────────────     ───────────────────────────</span></span>
<span class="line"><span>JVM (javac)                   Lua 5.0+</span></span>
<span class="line"><span>CPython                       Dalvik (Android)</span></span>
<span class="line"><span>WASM                          Android Runtime (ART)</span></span>
<span class="line"><span>.NET CLR (IL 层)              .NET CoreCLR (JIT 后)</span></span>
<span class="line"><span>V8 早期 Crankshaft            V8 Ignition (栈 + accumulator,折中)</span></span>
<span class="line"><span>PHP Zend Engine               Erlang BEAM</span></span>
<span class="line"><span>Smalltalk                     LuaJIT</span></span></code></pre></div><p><strong>特别注意 V8 Ignition 这个折中</strong>:名义上栈式,但有一个特殊的 <strong>accumulator 寄存器</strong>——上一条指令的结果默认留在 accumulator 里,下一条直接用,省 push/pop。<strong>接近寄存器式的性能 + 栈式的编译器简洁</strong>——V8 团队 2016 年的设计,叫 &quot;register-machine with accumulator&quot;。</p><hr><h2 id="四、为什么-lua-选寄存器式" tabindex="-1">四、为什么 Lua 选寄存器式 <a class="header-anchor" href="#四、为什么-lua-选寄存器式" aria-label="Permalink to &quot;四、为什么 Lua 选寄存器式&quot;">​</a></h2><p>Roberto Ierusalimschy(Lua 作者)团队 2005 年论文《The Implementation of Lua 5.0》:Lua 4.0 栈式换成 5.0 寄存器式后,<strong>字节码指令数减少 35%、总字节数减少 31%、解释速度提升 30-50%</strong>(取 benchmark)。</p><p>论文里的例子 <code>a = b + c * d</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>栈式 Lua 4.0:                  寄存器式 Lua 5.0:</span></span>
<span class="line"><span>GETGLOBAL b                    GETGLOBAL R0 &quot;b&quot;</span></span>
<span class="line"><span>GETGLOBAL c                    GETGLOBAL R1 &quot;c&quot;</span></span>
<span class="line"><span>GETGLOBAL d                    GETGLOBAL R2 &quot;d&quot;</span></span>
<span class="line"><span>MUL                            MUL  R1 R1 R2</span></span>
<span class="line"><span>ADD                            ADD  R0 R0 R1</span></span>
<span class="line"><span>SETGLOBAL a                    SETGLOBAL R0 &quot;a&quot;</span></span>
<span class="line"><span>(6 指令 + 5 次 push/pop)        (6 指令,无栈操作)</span></span></code></pre></div><p>Dalvik 设计文档(Dan Bornstein,Google IO 2008)几乎复述同样理由——<strong>Android 设备 2008 年是 200MHz CPU,dispatch 开销决定一切</strong>。</p><hr><h2 id="五、同一段-mochi-代码-两种字节码" tabindex="-1">五、同一段 Mochi 代码,两种字节码 <a class="header-anchor" href="#五、同一段-mochi-代码-两种字节码" aria-label="Permalink to &quot;五、同一段 Mochi 代码,两种字节码&quot;">​</a></h2><p>源码 <code>let c = a + b * 3</code>(a/b 已是局部变量):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>栈式(本系列实际用):              寄存器式(假想 Mochi-R,仿 Lua):</span></span>
<span class="line"><span>LOAD_LOCAL 0  ; push a            MUL    R3 R1 K0    ; R3 = b * 3</span></span>
<span class="line"><span>LOAD_LOCAL 1  ; push b            ADD    R2 R0 R3    ; R2(=c) = a + R3</span></span>
<span class="line"><span>CONST 0       ; push 3</span></span>
<span class="line"><span>MUL           ; b*3</span></span>
<span class="line"><span>ADD           ; a+b*3</span></span>
<span class="line"><span>STORE_LOCAL 2 ; c</span></span>
<span class="line"><span></span></span>
<span class="line"><span>(6 指令、6 dispatch、4 次栈操作)   (2 指令、2 dispatch、0 次栈操作)</span></span></code></pre></div><p>寄存器式<strong>指令数 1/3,dispatch 次数 1/3</strong>——这就是 Lua 论文里 30% 速度提升的来源。</p><hr><h2 id="六、寄存器分配的复杂性" tabindex="-1">六、寄存器分配的复杂性 <a class="header-anchor" href="#六、寄存器分配的复杂性" aria-label="Permalink to &quot;六、寄存器分配的复杂性&quot;">​</a></h2><p><strong>寄存器式的代价压在编译器身上</strong>:要决定<strong>每个中间值放进哪个虚拟寄存器</strong>——栈式编译器从不需要做(栈式是&quot;算出来自动入栈&quot;)。</p><p>工业级常用<strong>线性扫描(linear scan)寄存器分配</strong>(Poletto 1999):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 给每个变量算「活跃区间」(从第一次写到最后一次读)</span></span>
<span class="line"><span>2. 按起点排序,扫描每个区间:</span></span>
<span class="line"><span>     起点 → 分配空闲寄存器</span></span>
<span class="line"><span>     终点 → 释放回空闲集</span></span>
<span class="line"><span>3. 寄存器不够 → 溢出到栈帧额外槽(spill)</span></span></code></pre></div><p><strong>比图着色法快一个数量级</strong>,LLVM 早年 JIT、HotSpot client compiler 都在用。</p><p>Lua 用更简单的版本——<strong>编译期顺序分配,不优化</strong>。<code>lcode.c</code> 用一个 <code>freereg</code> 计数器,emit 一条指令就 +1,<strong>像在栈上分配,只是用编号代替</strong>。够 Lua 用 20 年。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Lua 编译器     1500 行 lcode.c     ← 寄存器分配 + 跳转修正 + 常量折叠</span></span>
<span class="line"><span>CPython        800 行 compile.c    ← 主要是 visit AST + emit</span></span></code></pre></div><p><strong>多出来的复杂度都在性能上挣回来了</strong>——工程取舍的经典案例。</p><hr><h2 id="七、为什么本系列-mochi-选栈式" tabindex="-1">七、为什么本系列 Mochi 选栈式 <a class="header-anchor" href="#七、为什么本系列-mochi-选栈式" aria-label="Permalink to &quot;七、为什么本系列 Mochi 选栈式&quot;">​</a></h2><p>四个理由,按重要性排:</p><ol><li><strong>教学</strong>:栈式编译器 80 行讲透;寄存器式要再讲一章寄存器分配</li><li><strong>可读</strong>:栈式反汇编像后缀表达式直观;寄存器式要看一堆 R0/R1/R2 编号</li><li><strong>JVM / CPython / WASM 都是栈式</strong>——读者读这些源码用得上</li><li><strong>24 篇写编译器</strong>——栈式编译器代码量少、跳转回填讲得透</li></ol><p>但<strong>写完 30 篇你想做下一步</strong>——给 Mochi 加个 register-based 后端、补线性扫描寄存器分配,是非常好的练习。<strong>LuaJIT 的 Mike Pall 就是这样把 Lua 解释器从 130MB/s 推到 1GB/s</strong>。</p><hr><h2 id="八、工业指针" tabindex="-1">八、工业指针 <a class="header-anchor" href="#八、工业指针" aria-label="Permalink to &quot;八、工业指针&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>文件</th><th>看什么</th></tr></thead><tbody><tr><td>Lua</td><td><code>src/lopcodes.h</code></td><td>注释最清晰的寄存器式指令集定义,A/B/C 三操作数编码</td></tr><tr><td>Lua</td><td><code>src/lcode.c</code></td><td>寄存器分配 + 跳转修正,寄存器式编译器范本</td></tr><tr><td>Dalvik</td><td>Android <code>dalvik/docs/dalvik-bytecode.html</code></td><td>寄存器编号 + 指令格式表</td></tr><tr><td>LuaJIT</td><td><code>src/lj_bcdef.h</code> <code>src/lj_bcread.c</code></td><td>改进版 Lua 字节码,加类型 hint</td></tr><tr><td>V8 Ignition</td><td><code>src/interpreter/bytecode-array-builder.cc</code></td><td>看 accumulator 怎么省 push/pop</td></tr><tr><td>Erlang BEAM</td><td><code>erts/emulator/beam/beam_emu.c</code></td><td>寄存器式 + threaded code 双特性</td></tr><tr><td>.NET RyuJIT</td><td><code>src/coreclr/jit/lsra.cpp</code></td><td>工业级线性扫描寄存器分配,3000+ 行</td></tr></tbody></table><p>读源码顺序:<strong><code>lopcodes.h</code> 一定要看</strong>,100 行注释讲完整套寄存器式 VM 的设计哲学,比任何教科书都直接。</p><hr><h2 id="九、mochi-这里偷懒了" tabindex="-1">九、Mochi 这里偷懒了 <a class="header-anchor" href="#九、mochi-这里偷懒了" aria-label="Permalink to &quot;九、Mochi 这里偷懒了&quot;">​</a></h2><ul><li><strong>不实现寄存器式</strong>——本系列只做栈式,以免 24 篇编译器讲不透</li><li><strong>不做对比 benchmark</strong>——理论 30% 提速,但 fair compare 得两个版本都做 IC,工作量太大</li><li><strong>想自己做</strong>:从 AST 出发,改 emit 函数为「分配虚拟寄存器 + emit 三操作数指令」,200 行能跑;先用 Lua 那种&quot;顺序分配 + freereg 计数&quot;,跑通再上线性扫描</li></ul><hr><p>下一篇:<code>24-编译器-AST到字节码.md</code>——<strong>全系列最容易卡的一篇</strong>。把前面 8 章的树遍历求值器换皮:递归返回值的地方现在 emit 字节码;if 直接执行的地方要做<strong>跳转回填</strong>(backpatching)。讲清回填这一招,你就拿到了所有现代编译器后端的入场券。</p>`,55)])])}const g=s(o,[["render",p]]);export{u as __pageData,g as default};
